package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private PrintStream originalOut;

    @BeforeEach
    void setUp() {
        // Save the original System.out
        originalOut = System.out;
    }

    @AfterEach
    void tearDown() {
        // Restore the original System.out
        System.setOut(originalOut);
    }

    @Test
    void testPrinterReturnsNonNullCSVPrinter() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVPrinter printer = format.printer();
        assertNotNull(printer, "printer() should not return null");
        // The CSVPrinter should be constructed with System.out and this CSVFormat instance
        // We can verify the printer's underlying Appendable is System.out by reflection
        // But CSVPrinter's fields are not provided, so just check class type
        assertEquals(CSVPrinter.class, printer.getClass());
    }

    @Test
    void testPrinterWithCustomFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.DEFAULT.withDelimiter(';').withQuote('\'');
        CSVPrinter printer = customFormat.printer();
        assertNotNull(printer);
        assertEquals(CSVPrinter.class, printer.getClass());
    }
}
